// Tests for image-fft-frf: row-/column-tiled 2D FFT structured via FRF.
// Verifies bit-exact parity with fft2/ifft2 from fft2.ts at tiles=1, the
// same parity when callers pass an advisory tiles hint (>=2), round-trip
// fidelity, ifft2FRF parity, and input validation.

import { describe, it, expect } from 'vitest';
import { fft2, ifft2, type Complex2D } from '../src/fft2';
import { fft2FRF, ifft2FRF } from '../src/image-fft-frf';

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

function randomPlane(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h);
  const rand = lcg(seed);
  for (let i = 0; i < out.length; i++) out[i] = rand();
  return out;
}

function maxAbsDelta(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`length mismatch ${a.length} vs ${b.length}`);
  }
  let m = 0;
  for (let i = 0; i < a.length; i++) {
    const d = Math.abs(a[i]! - b[i]!);
    if (d > m) m = d;
  }
  return m;
}

function rmse(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`length mismatch ${a.length} vs ${b.length}`);
  }
  let s = 0;
  for (let i = 0; i < a.length; i++) {
    const d = a[i]! - b[i]!;
    s += d * d;
  }
  return Math.sqrt(s / a.length);
}

function complexEqualBitExact(a: Complex2D, b: Complex2D): void {
  expect(a.w).toBe(b.w);
  expect(a.h).toBe(b.h);
  expect(maxAbsDelta(a.re, b.re)).toBe(0);
  expect(maxAbsDelta(a.im, b.im)).toBe(0);
}

describe('fft2FRF tiles=1 matches fft2 bit-exact', () => {
  it('produces identical Complex2D for a 64x64 deterministic plane', async () => {
    const w = 64,
      h = 64;
    const plane = randomPlane(w, h, 0xc0ffee);
    const ref = fft2(plane, w, h);
    const got = await fft2FRF({ real: plane, width: w, height: h, tiles: 1 });
    complexEqualBitExact(got, ref);
  });

  it('also matches when tiles is omitted (default 1)', async () => {
    const w = 64,
      h = 64;
    const plane = randomPlane(w, h, 0xdeadbeef);
    const ref = fft2(plane, w, h);
    const got = await fft2FRF({ real: plane, width: w, height: h });
    complexEqualBitExact(got, ref);
  });
});

describe('fft2FRF round-trip', () => {
  it('ifft2FRF(fft2FRF(plane)) recovers input within 1e-6 RMSE', async () => {
    const w = 64,
      h = 64;
    const plane = randomPlane(w, h, 1234);
    const spectrum = await fft2FRF({ real: plane, width: w, height: h });
    const recovered = await ifft2FRF({ spectrum });
    expect(recovered.length).toBe(plane.length);
    expect(rmse(recovered, plane)).toBeLessThan(1e-6);
  });
});

describe('fft2FRF tiles>=2 (advisory) matches tiles=1', () => {
  it('tiles=4 produces same output as tiles=1', async () => {
    const w = 64,
      h = 64;
    const plane = randomPlane(w, h, 42);
    const t1 = await fft2FRF({ real: plane, width: w, height: h, tiles: 1 });
    const t4 = await fft2FRF({ real: plane, width: w, height: h, tiles: 4 });
    complexEqualBitExact(t4, t1);
  });

  it('tiles=8 produces same output as tiles=1', async () => {
    const w = 32,
      h = 32;
    const plane = randomPlane(w, h, 7);
    const t1 = await fft2FRF({ real: plane, width: w, height: h, tiles: 1 });
    const t8 = await fft2FRF({ real: plane, width: w, height: h, tiles: 8 });
    complexEqualBitExact(t8, t1);
  });
});

describe('ifft2FRF parity with ifft2', () => {
  it('produces identical Float32Array on the same spectrum', async () => {
    const w = 32,
      h = 32;
    const plane = randomPlane(w, h, 0xbeef);
    const spectrum = fft2(plane, w, h);
    const ref = ifft2(spectrum);
    const got = await ifft2FRF({ spectrum });
    expect(got.length).toBe(ref.length);
    expect(maxAbsDelta(got, ref)).toBe(0);
  });

  it('matches even when caller passes a tiles hint', async () => {
    const w = 32,
      h = 32;
    const plane = randomPlane(w, h, 0xfeed);
    const spectrum = fft2(plane, w, h);
    const ref = ifft2(spectrum);
    const got = await ifft2FRF({ spectrum, tiles: 4 });
    expect(maxAbsDelta(got, ref)).toBe(0);
  });
});

describe('fft2FRF validation', () => {
  it('throws on non-power-of-two width', async () => {
    await expect(
      fft2FRF({ real: new Float32Array(48 * 32), width: 48, height: 32 }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on non-power-of-two height', async () => {
    await expect(
      fft2FRF({ real: new Float32Array(32 * 48), width: 32, height: 48 }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on zero width', async () => {
    await expect(
      fft2FRF({ real: new Float32Array(0), width: 0, height: 32 }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on zero height', async () => {
    await expect(
      fft2FRF({ real: new Float32Array(0), width: 32, height: 0 }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on bad real.length', async () => {
    await expect(
      fft2FRF({ real: new Float32Array(10), width: 32, height: 32 }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on tiles=0', async () => {
    await expect(
      fft2FRF({
        real: new Float32Array(32 * 32),
        width: 32,
        height: 32,
        tiles: 0,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on negative tiles', async () => {
    await expect(
      fft2FRF({
        real: new Float32Array(32 * 32),
        width: 32,
        height: 32,
        tiles: -1,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on non-integer tiles', async () => {
    await expect(
      fft2FRF({
        real: new Float32Array(32 * 32),
        width: 32,
        height: 32,
        tiles: 1.5,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on bad concurrency', async () => {
    await expect(
      fft2FRF({
        real: new Float32Array(32 * 32),
        width: 32,
        height: 32,
        concurrency: 0,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });
});

describe('ifft2FRF validation', () => {
  it('throws on non-power-of-two w', async () => {
    const bad: Complex2D = {
      re: new Float32Array(48 * 32),
      im: new Float32Array(48 * 32),
      w: 48,
      h: 32,
    };
    await expect(ifft2FRF({ spectrum: bad })).rejects.toBeInstanceOf(
      RangeError,
    );
  });

  it('throws on non-power-of-two h', async () => {
    const bad: Complex2D = {
      re: new Float32Array(32 * 48),
      im: new Float32Array(32 * 48),
      w: 32,
      h: 48,
    };
    await expect(ifft2FRF({ spectrum: bad })).rejects.toBeInstanceOf(
      RangeError,
    );
  });

  it('throws when re/im length disagrees with w*h', async () => {
    const bad: Complex2D = {
      re: new Float32Array(8),
      im: new Float32Array(8),
      w: 32,
      h: 32,
    };
    await expect(ifft2FRF({ spectrum: bad })).rejects.toBeInstanceOf(
      RangeError,
    );
  });

  it('throws on tiles=0', async () => {
    const plane = randomPlane(16, 16, 1);
    const spectrum = fft2(plane, 16, 16);
    await expect(
      ifft2FRF({ spectrum, tiles: 0 }),
    ).rejects.toBeInstanceOf(RangeError);
  });
});
